// Extract and normalise Telegram message fields
const msg = $input.item.json.message ?? $input.item.json;
const userId   = String(msg.from?.id ?? 'unknown');
const username = msg.from?.username ?? msg.from?.first_name ?? userId;
const chatId   = String(msg.chat?.id ?? msg.from?.id ?? 'unknown');
const text     = msg.text ?? '';
const sessionId = `telegram-${chatId}`;
return [{ json: {
  user_message: text,
  session_id: sessionId,
  chat_id: chatId,
  user: {
    user_id: userId,
    display_name: username,
    channel: 'telegram',
    tenant: 'threatlabs',
  }
} }];

// Merge memory rows back with normalised input
const input = $('Normalise Input').first().json;
const memoryRows = $input.all().map(i => i.json);
// Reverse so oldest first for LLM context
const history = [...memoryRows].reverse().map(r => ({ role: r.role, content: r.content }));
return [{ json: { ...input, history } }];

// Parse LLM output and detect clarification requests
const raw = $input.item.json.output ?? $input.item.json.text ?? '';
let llm_output;
try {
  // Strip markdown code fences if present
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  llm_output = JSON.parse(cleaned);
} catch(e) {
  // LLM returned prose — treat as clarification needed
  llm_output = { clarification_needed: true, clarification_question: raw };
}
const input = $('Merge Memory').first().json;
return [{ json: { ...input, llm_output, needs_clarification: llm_output.clarification_needed === true } }];

// See n8n/gateway/code/build-proposed-action.js
const input = $input.item.json;
const llm = input.llm_output;
const user = input.user;
const session = input.session_id;
const RISK_MAP = { 'read-only': 'low', 'read-write': 'medium', 'admin': 'high' };
const HIGH_RISK_SYSTEMS = ['shuffle','xtm','dfir-iris'];
function deriveRiskLevel(mode, targetSystem) {
  let level = RISK_MAP[mode] ?? 'medium';
  if (HIGH_RISK_SYSTEMS.includes(targetSystem)) { const order = ['low','medium','high','critical']; const idx = order.indexOf(level); if (idx < order.length - 1) level = order[idx + 1]; }
  return level;
}
function sanitiseParams(params) { if (!params || typeof params !== 'object') return {}; const safe = {}; for (const [k,v] of Object.entries(params)) { if (typeof v === 'string' && v.length > 500) continue; safe[k] = v; } return safe; }
const crypto = require('crypto');
const id = crypto.randomUUID();
const mode = llm.action?.mode ?? 'read-only';
const targetSystem = llm.action?.target_system ?? 'unknown';
const riskLevel = deriveRiskLevel(mode, targetSystem);
const proposedAction = {
  id,
  timestamp: new Date().toISOString(),
  agent: { name: 'yaoc2-threat-analyst', version: '2026.03.1', session_id: session },
  requester: { user_id: user.user_id, display_name: user.display_name, channel: user.channel, tenant: user.tenant ?? 'threatlabs' },
  intent: { title: llm.intent?.title ?? 'Agent action', description: llm.intent?.description ?? '', user_prompt: input.user_message ?? '' },
  action: { type: llm.action?.type ?? 'workflow', name: llm.action?.name, target_system: targetSystem, mode, parameters: sanitiseParams(llm.action?.parameters) },
  risk: { level: riskLevel, reasons: llm.risk_reasons ?? [], estimated_impact: llm.estimated_impact ?? '' },
  constraints: { must_complete_before: new Date(Date.now() + 2*60*60*1000).toISOString(), max_cost_units: 20, dry_run: false },
  policy: { policy_set: 'default-threatlab', required_approvals: [] },
  llm_explanation: { reasoning_summary: llm.reasoning_summary ?? '', alternatives_considered: llm.alternatives_considered ?? [] }
};
return [{ json: { ...input, proposed_action: proposedAction } }];

// Handle gateway response and build user-facing reply
const gatewayBody = $input.item.json.body ?? $input.item.json;
const statusCode = $input.item.json.statusCode ?? 200;
const input = $('Build ProposedAction').first().json;
let replyText;
if (statusCode === 200 && gatewayBody.final_status === 'executed') {
  replyText = `✅ *Done!*\n${gatewayBody.result_summary}`;
} else if (statusCode === 202) {
  replyText = `⏳ *Approval required*\n${gatewayBody.message}\n\nYour request ID: \`${gatewayBody.proposed_action_id}\``;
} else if (statusCode === 403) {
  replyText = `🚫 *Action denied by policy*\n${gatewayBody.message}`;
} else if (statusCode === 400) {
  replyText = `⚠️ *Invalid request*\n${gatewayBody.message}`;
} else {
  replyText = `❌ *Gateway error (${statusCode})*\nPlease try again or contact your analyst.`;
}
return [{ json: { ...input, gateway_response: gatewayBody, gateway_status: statusCode, reply_text: replyText } }];
